const tz = 'Europe/Paris';
const now = new Date();
const dayName = new Intl.DateTimeFormat('fr-FR', {timeZone: tz, weekday: 'long'}).format(now);
const weatherRes = $node['HTTP GET Weather'].json;
const tempMax = weatherRes.daily?.apparent_temperature_max?.[0] || 'N/A';
const tempMin = weatherRes.daily?.apparent_temperature_min?.[0] || 'N/A';
let weatherEmoji = '☀️';
if (tempMax < 5) weatherEmoji = '❄️';
else if (tempMax < 10) weatherEmoji = '🌧️';
else if (tempMax < 15) weatherEmoji = '☁️';
else if (tempMax > 20) weatherEmoji = '🌞';
const weatherStr = `${weatherEmoji} Nogent-le-Roi : ${tempMin}°C → ${tempMax}°C`;
const newsFR = $node['HTTP GET News FR'].json.articles || [];
const newsAI = $node['HTTP GET News AI'].json.articles || [];
const motivations = [
  '🎯 1% mieux aujourd\'hui.',
  '🔥 Petit pas, gros impact.',
  '🧠 La constance bat la motivation.',
  '🚀 Fais simple, fais-le.',
  '💪 H2 = croissance, pas confort.',
  '⚡ Expert Local t\'attend.',
  '🏗️ Construis ton empire, brique par brique.',
  '🎬 Action > Réflexion.',
  '🧱 Les fondations d\'abord, les détails ensuite.'
];
const mot = motivations[Math.floor(Math.random() * motivations.length)];
return [{
  json: {
    weatherStr,
    newsFR,
    newsAI,
    mot,
    dayName
  }
}];

const ctx = $node['Code JS : Build Morning Data'].json;
const objRecords = $node['Notion : Query Objectifs'].json;
const batchRecords = $node['Notion : Query Batch Results'].json;

// === HELPERS ===
function extractText(prop) {
  if (!prop || prop.type !== 'title') return 'Sans titre';
  return (prop.title || []).map(x => x.plain_text).join('').trim() || 'Sans titre';
}
function extractSelect(prop) {
  if (!prop) return '';
  if (prop.type === 'select') return prop.select?.name || '';
  if (prop.type === 'status') return prop.status?.name || '';
  return '';
}

// === OBJECTIFS H2 ===
const objItems = Array.isArray(objRecords) ? objRecords : (objRecords?.results || [objRecords]).filter(r => r && r.properties);
const h2_today = [];
for (const r of objItems) {
  const props = r.properties || r;
  const hz = extractSelect(props['Horizon']) || '';
  const st = extractSelect(props['Statut']) || '';
  if (hz.includes('H2') && !st.includes('Terminé') && !st.includes('Abandonné')) {
    h2_today.push(extractText(props['Objectif']));
  }
  if (h2_today.length >= 3) break;
}

// === BATCH RESULTS (dernière nuit) ===
const batchItems = Array.isArray(batchRecords) ? batchRecords : (batchRecords?.results || [batchRecords]).filter(r => r && r.properties);
const today = new Date().toISOString().split('T')[0];
const batchDone = [];
const batchFailed = [];
let batchCostTotal = 0;

for (const r of batchItems) {
  const props = r.properties || r;

  // Vérifier tags batch
  const tags = (props.Tags?.multi_select || []).map(t => t.name.toLowerCase());
  if (!tags.includes('batch')) continue;

  const statut = extractSelect(props['Statut']);
  const nom = extractText(props['Nom'] || props['Name']);
  const cost = props['Tokens_Cost']?.number || 0;

  // Vérifier date (dernières 24h)
  const editedTime = r.last_edited_time || '';
  if (editedTime && editedTime.startsWith(today)) {
    if (statut === 'Terminé') {
      batchDone.push(nom);
      batchCostTotal += cost;
    } else if (statut === 'Échec') {
      batchFailed.push(nom);
    }
  }
}

// === BUILD MESSAGE ===
let msg = `☀️ Bonjour Antoine ! (${ctx.dayName.charAt(0).toUpperCase() + ctx.dayName.slice(1)})\n\n`;
msg += `${ctx.weatherStr}\n\n`;

// Section Batch (si résultats cette nuit)
if (batchDone.length > 0 || batchFailed.length > 0) {
  msg += `🌙 <b>Batch nocturne :</b>\n`;
  if (batchDone.length > 0) {
    msg += `  ✅ ${batchDone.length} tâche(s) terminée(s)`;
    if (batchCostTotal > 0) msg += ` (${Math.round(batchCostTotal * 10000) / 10000}€)`;
    msg += '\n';
    batchDone.forEach(b => { msg += `    • ${b.substring(0, 40)}\n`; });
  }
  if (batchFailed.length > 0) {
    msg += `  ❌ ${batchFailed.length} en échec\n`;
    batchFailed.forEach(b => { msg += `    • ${b.substring(0, 40)}\n`; });
  }
  msg += '  📋 /batch report pour le détail\n\n';
}

// Section H2
if (h2_today.length) {
  msg += `🔵 <b>H2 d'aujourd'hui :</b>\n`;
  h2_today.forEach(b => { msg += `  • ${b}\n`; });
  msg += '\n';
} else {
  msg += '📌 Aucun H2 planifié — tu veux en ajouter un ?\n\n';
}

// Section News FR
if (ctx.newsFR.length) {
  msg += `📰 <b>Actus FR</b>\n`;
  ctx.newsFR.slice(0, 3).forEach((article, idx) => {
    const title = (article.title || '').substring(0, 50);
    msg += `${idx + 1}. ${title}\n`;
  });
  msg += '\n';
}

// Section News AI
if (ctx.newsAI.length) {
  msg += `🤖 <b>IA & Tech</b>\n`;
  ctx.newsAI.slice(0, 3).forEach((article, idx) => {
    const title = (article.title || '').substring(0, 50);
    msg += `${idx + 1}. ${title}\n`;
  });
  msg += '\n';
}

msg += ctx.mot;

return [{ json: { chatId: 8572640484, text: msg.slice(0, 4096), parse_mode: 'HTML' } }];

const items = $input.all();
const res = items.map(i => i.json);

function extractText(prop) {
  if (!prop || prop.type !== 'title') return 'Tâche';
  return (prop.title || []).map(x => x.plain_text).join('').trim() || 'Tâche';
}
function extractSelect(prop) {
  if (!prop) return '';
  if (prop.type === 'select') return prop.select?.name || '';
  if (prop.type === 'status') return prop.status?.name || '';
  return '';
}

let msg = '⏰ <b>Pause déj</b> : comment tu avances ?\n\n';

const h1Items = [];
for (const r of res) {
  const props = r.properties || r;
  const hz = extractSelect(props['Horizon']) || '';
  const st = extractSelect(props['Statut']) || '';
  if (hz.includes('H1') && !st.includes('Terminé')) {
    h1Items.push(extractText(props['Objectif']));
  }
  if (h1Items.length >= 3) break;
}

if (h1Items.length) {
  msg += '🚀 H1 en cours :\n';
  h1Items.forEach(t => { msg += `  • ${t}\n`; });
} else {
  msg += '✅ Tous tes H1 sont couverts !\n';
}
msg += '\n💪 Après manger : retour en H2 ?';
return [{ json: { chatId: 8572640484, text: msg.slice(0, 400), parse_mode: 'HTML' } }];

const items = $input.all();
const res = items.map(i => i.json);

// Filtrer victoires d'aujourd'hui
const today = new Date().toISOString().split('T')[0];
const todayVictoires = res.filter(r => {
  const props = r.properties || r;
  const dateVal = props.Date?.date?.start || r.created_time || '';
  return dateVal.startsWith(today);
});

const totalPoints = todayVictoires.reduce((sum, r) => {
  const props = r.properties || r;
  return sum + (props.Points?.number || 0);
}, 0);

let msg = `📊 <b>Recap du jour</b>\n\n`;
if (todayVictoires.length) {
  msg += `✅ ${todayVictoires.length} victoire(s) loggée(s)\n🏆 +${totalPoints} points\n\n`;
} else {
  msg += 'Pas de victoires loggées aujourd\'hui.\n/victoire pour en ajouter une !\n\n';
}
msg += '💭 Qu\'as-tu appris ?\n🌙 Bonne nuit ! Demain = nouveau jour.';
return [{ json: { chatId: 8572640484, text: msg.slice(0, 400), parse_mode: 'HTML' } }];

const items = $input.all();
const res = items.map(i => i.json);

function extractSelect(prop) {
  if (!prop) return '';
  if (prop.type === 'select') return prop.select?.name || '';
  if (prop.type === 'status') return prop.status?.name || '';
  return '';
}

const h2Done = res.filter(r => {
  const props = r.properties || r;
  const hz = extractSelect(props['Horizon']) || '';
  const st = extractSelect(props['Statut']) || '';
  return hz.includes('H2') && st.includes('Terminé');
}).length;

const h2Total = res.filter(r => {
  const props = r.properties || r;
  const hz = extractSelect(props['Horizon']) || '';
  return hz.includes('H2');
}).length;

let msg = `🎯 <b>QG STRATÉGIQUE — Semaine</b>\n\n📊 Objectifs H2 :\n   ${h2Done}/${h2Total} complétés\n\n`;
if (h2Done >= 2) msg += `🏆 Excellente semaine !\n`;
else if (h2Done >= 1) msg += `✅ Bon progrès.\n`;
else msg += `⚠️ À accélérer.\n`;
msg += `\n💡 Réflexions pour la suite ?\n🎬 Qu'est-ce qui a marché ? Qu'est-ce qui a bloqué ?\n\n`;
msg += `📌 Rappel : Un bloc 🔵 peut être DÉPLACÉ, jamais ANNULÉ. 💪`;
return [{ json: { chatId: 8572640484, text: msg.slice(0, 500), parse_mode: 'HTML' } }];
